+fn skip_type_annotation(content: &str, mut index: usize) -> Option<usize> {
+    let mut paren_depth = 0usize;
+    let mut bracket_depth = 0usize;
+    let mut brace_depth = 0usize;
+    let mut angle_depth = 0usize;
+    let mut string_delimiter: Option<char> = None;
+    let mut escaped = false;
+
+    while index < content.len() {
+        if let Some(next_index) = skip_comment(content, index) {
+            index = next_index;
+            continue;
+        }
+
+        let ch = content[index..].chars().next()?;
+        if let Some(delimiter) = string_delimiter {
+            index += ch.len_utf8();
+            if escaped {
+                escaped = false;
+                continue;
+            }
+            if ch == '\\' {
+                escaped = true;
+                continue;
+            }
+            if ch == delimiter {
+                string_delimiter = None;
+            }
+            continue;
+        }
+
+        match ch {
+            '"' | '\'' | '`' => {
+                string_delimiter = Some(ch);
+                index += ch.len_utf8();
+            }
+            '(' => {
+                paren_depth += 1;
+                index += ch.len_utf8();
+            }
+            ')' => {
+                paren_depth = paren_depth.saturating_sub(1);
+                index += ch.len_utf8();
+            }
+            '[' => {
+                bracket_depth += 1;
+                index += ch.len_utf8();
+            }
+            ']' => {
+                bracket_depth = bracket_depth.saturating_sub(1);
+                index += ch.len_utf8();
+            }
+            '{' => {
+                brace_depth += 1;
+                index += ch.len_utf8();
+            }
+            '}' => {
+                brace_depth = brace_depth.saturating_sub(1);
+                index += ch.len_utf8();
+            }
+            '<' => {
+                angle_depth += 1;
+                index += ch.len_utf8();
+            }
+            '>' => {
+                angle_depth = angle_depth.saturating_sub(1);
+                index += ch.len_utf8();
+            }
+            '=' if paren_depth == 0
+                && bracket_depth == 0
+                && brace_depth == 0
+                && angle_depth == 0
+                && !content[index..].starts_with("=>") =>
+            {
+                return Some(index);
+            }
+            ';' | '\n'
+                if paren_depth == 0
+                    && bracket_depth == 0
+                    && brace_depth == 0
+                    && angle_depth == 0 =>
+            {
+                return None;
+            }
+            _ => {
+                index += ch.len_utf8();
+            }
+        }
+    }
+
+    None
+}
+
+fn skip_whitespace_and_comments(content: &str, mut index: usize) -> usize {
+    while index < content.len() {
+        let remaining = &content[index..];
+        let Some(ch) = remaining.chars().next() else {
+            break;
+        };
+        if ch.is_whitespace() {
+            index += ch.len_utf8();
+            continue;
+        }
+        if let Some(next_index) = skip_comment(content, index) {
+            index = next_index;
+            continue;
+        }
+        break;
+    }
+    index
+}
+
+fn skip_comment(content: &str, index: usize) -> Option<usize> {
+    let remaining = &content[index..];
+    if remaining.starts_with("//") {
+        return Some(
+            remaining
+                .find('\n')
+                .map(|offset| index + offset)
+                .unwrap_or(content.len()),
+        );
+    }
+    if remaining.starts_with("/*") {
+        return Some(
+            remaining
+                .find("*/")
+                .map(|offset| index + offset + 2)
+                .unwrap_or(content.len()),
+        );
+    }
+    None
+}
